"token,omitempty\"`\n\tNamespace  string `json:\"namespace,omitempty\" mapstructure:\"namespace\" yaml:\"namespace,omitempty\"`\n}\n\n// GCPProviderConfig contains configuration for Google Cloud Secret Manager provider.\ntype GCPProviderConfig struct {\n\tEnabled     bool   `json:\"enabled\" mapstructure:\"enabled\" yaml:\"enabled\"`\n\tProject     string `json:\"project,omitempty\" mapstructure:\"project\" yaml:\"project,omitempty\"`\n\tLocation    string `json:\"location,omitempty\" mapstructure:\"location\" yaml:\"location,omitempty\"`\n\tCredentials string `json:\"credentials,omitempty\" mapstructure:\"credentials\" yaml:\"credentials,omitempty\"`\n}\n\n// AWSProviderConfig contains configuration for AWS Secrets Manager provider.\n// Region is determined by the AWS SDK's default configuration (e.g., AWS_DEFAULT_REGION environment variable).\ntype AWSProviderConfig struct {\n\tEnabled     bool   `json:\"enabled\" mapstructure:\"enabled\" yaml:\"enabled\"`\n\tEndpointURL string `json:\"endpoint_url,omitempty\" mapstructure:\"endpoint_url\" yaml:\"endpoint_url,omitempty\"`\n}\n\n// AzureProviderConfig contains configuration for Azure Key Vault provider.\n// Authentication uses DefaultAzureCredential which supports managed identity,\n// environment variables (AZURE_CLIENT_ID, AZURE_TENANT_ID, AZURE_CLIENT_SECRET),\n// Azure CLI, and other credential sources.\ntype AzureProviderConfig struct {\n\tEnabled  bool   `json:\"enabled\" mapstructure:\"enabled\" yaml:\"enabled\"`\n\tVaultURL string `json:\"vault_url,omitempty\" mapstructure:\"vault_url\" yaml:\"vault_url,omitempty\"`\n}\n\n// SecretReference represents a reference to a secret value.\ntype SecretReference struct {\n\tProvider string `json:\"provider\" mapstructure:\"provider\" yaml:\"provider\"`\n\tPath     string `json:\"path\" mapstructure:\"path\" yaml:\"path\"`\n\tKey      string `json:\"key\" mapstructure:\"key\" yaml:\"key\"`\n}\n\nfunc (s *SecretsConfig) setDefaults(v *viper.Viper) { //nolint:unused // used by config system via reflection\n\t// File provider defaults\n\tv.SetDefault(\"secrets.providers.file.enabled\", false)\n\tv.SetDefault(\"secrets.providers.file.base_path\", \"/etc/flipt/secrets\")\n\n\t// Vault provider defaults\n\tv.SetDefault(\"secrets.providers.vault.enabled\", false)\n\tv.SetDefault(\"secrets.providers.vault.mount\", \"secret\")\n\tv.SetDefault(\"secrets.providers.vault.auth_method\", \"token\")\n\n\t// GCP provider defaults\n\tv.SetDefault(\"secrets.providers.gcp.enabled\", false)\n\n\t// AWS provider defaults\n\tv.SetDefault(\"secrets.providers.aws.enabled\", false)\n\n\t// Azure provider defaults\n\tv.SetDefault(\"secrets.providers.azure.enabled\", false)\n}\n\nfunc (s *SecretsConfig) validate() error {\n\t// Validate file provider\n\tif s.Providers.File != nil && s.Providers.File.Enabled {\n\t\tif s.Providers.File.BasePath == \"\" {\n\t\t\treturn errFieldRequired(\"secrets.providers.file\", \"base_path\")\n\t\t}\n\t}\n\n\t// Validate vault provider\n\tif s.Providers.Vault != nil && s.Providers.Vault.Enabled {\n\t\tif s.Providers.Vault.Address == \"\" {\n\t\t\treturn errFieldRequired(\"secrets.providers.vault\", \"address\")\n\t\t}\n\n\t\tswitch s.Providers.Vault.AuthMethod {\n\t\tcase \"token\":\n\t\t\tif s.Providers.Vault.Token == \"\" {\n\t\t\t\treturn errFieldRequired(\"secrets.providers.vault\", \"token\")\n\t\t\t}\n\t\tcase \"kubernetes\":\n\t\t\tif s.Providers.Vault.Role == \"\" {\n\t\t\t\treturn errFieldRequired(\"secrets.providers.vault\", \"role\")\n\t\t\t}\n\t\tcase \"approle\":\n\t\t\tif s.Providers.Vault.Role == \"\" {\n\t\t\t\treturn errFieldRequired(\"secrets.providers.vault\", \"role\")\n\t\t\t}\n\t\tdefault:\n\t\t\treturn errFieldWrap(\"secrets.providers.vault\", \"auth_method\", fmt.Errorf(\"unsupported auth method: %s\", s.Providers.Vault.AuthMethod))\n\t\t}\n\n\t\t// Note: License validation is done at runtime when the provider is instantiated\n\t\t// This allows the config to be valid but the feature to fail if no license is present\n\t}\n\n\t// Validate GCP provider\n\tif s.Providers.GCP != nil && s.Providers.GCP.Enabled {\n\t\tif s.Providers.GCP.Project == \"\" {\n\t\t\treturn errFieldRequired(\"secrets.providers.gcp\", \"project\")\n\t\t}\n\t}\n\n\t// AWS provider has no required fields beyond \"enabled\".\n\t// Region is resolved by the AWS SDK from the environment (e.g., AWS_DEFAULT_REGION).\n\n\t// Validate Azure provider\n\tif s.Providers.Azure != nil && s.Providers.Azure.Enabled {\n\t\tif s.Providers.Azure.VaultURL == \"\" {\n\t\t\treturn errFieldRequired(\"secrets.providers.azure\", \"vault_url\")\n\t\t}\n\t}\n\n\treturn nil\n}\n\n// EnabledProviders returns a list of enabled provider names.\nfunc (s *SecretsConfig) EnabledProviders() []string {\n\tvar providers []string\n\n\tif s.Providers.File != nil && s.Providers.File.Enabled {\n\t\tproviders = append(providers, \"file\")\n\t}\n\n\tif s.Providers.Vault != nil && s.Providers.Vault.Enabled {\n\t\tproviders = append(providers, \"vault\")\n\t}\n\n\tif s.Providers.GCP != nil && s.Providers.GCP.Enabled {\n\t\tproviders = append(providers, \"gcp\")\n\t}\n\n\tif s.Providers.AWS != nil && s.Providers.AWS.Enabled {\n\t\tproviders = append(providers, \"aws\")\n\t}\n\n\tif s.Providers.Azure != nil && s.Providers.Azure.Enabled {\n\t\tproviders = append(providers, \"azure\")\n\t}\n\n\treturn providers\n}\n\n// Validate checks if a secret reference is valid.\nfunc (r SecretReference) Validate() error {\n\tif r.Provider == \"\" {\n\t\treturn errFieldRequired(\"secret_reference\", \"provider\")\n\t}\n\tif r.Path == \"\" {\n\t\treturn errFieldRequired(\"secret_reference\", \"path\")\n\t}\n\tif r.Key == \"\" {\n\t\treturn errFieldRequired(\"secret_reference\", \"key\")\n\t}\n\treturn nil\n}\n", "numLines": 186, "startLine": 1, "totalLines": 186}}

