    35→func NewStore(dir string) (*Store, error) {
    36→	stat, err := os.Stat(dir)
    37→	if err != nil {
    38→		return nil, err
    39→	}
    40→
    41→	if !stat.IsDir() {
    42→		return nil, fmt.Errorf("expected directory at %q, found %q", dir, stat.Mode())
    43→	}
    44→
    45→	return &Store{dir}, nil
    46→}
