    48→func (s *Store) List() (bunches []Bunch, _ error) {
    49→	fi, err := os.Open(s.dir)
    50→	if err != nil {
    51→		return nil, err
    52→	}
    53→
    54→	defer fi.Close()
    55→
    56→	entries, err := fi.ReadDir(-1)
    57→	if err != nil {
    58→		return nil, err
    59→	}
    60→
    61→	for _, entry := range entries {
    62→		bytes, err := os.ReadFile(filepath.Join(s.dir, entry.Name(), v1.ImageIndexFile))
    63→		if err != nil {
    64→			if errors.Is(err, os.ErrNotExist) {
    65→				return nil, nil
    66→			}
    67→
    68→			return nil, err
    69→		}
    70→
    71→		var index v1.Index
    72→		if err := json.Unmarshal(bytes, &index); err != nil {
    73→			return nil, err
    74→		}
    75→
    76→		for _, manifest := range index.Manifests {
    77→			digest := manifest.Digest
    78→			path := filepath.Join(s.dir, entry.Name(), "blobs", digest.Algorithm().String(), digest.Hex())
    79→			bytes, err := os.ReadFile(path)
    80→			if err != nil {
    81→				return nil, err
    82→			}
    83→
    84→			var man v1.Manifest
    85→			if err := json.Unmarshal(bytes, &man); err != nil {
    86→				return nil, err
    87→			}
    88→
    89→			bunch := Bunch{
    90→				Digest:     manifest.Digest,
    91→				Repository: entry.Name(),
    92→				Tag:        manifest.Annotations[v1.AnnotationRefName],
    93→			}
    94→
    95→			bunch.CreatedAt, err = parseCreated(man.Annotations)
    96→			if err != nil {
    97→				return nil, err
    98→			}
    99→
   100→			bunches = append(bunches, bunch)
   101→		}
   102→	}
   103→
   104→	return
   105→}
