   117→func (s *Store) Create(ctx context.Context, src fs.FS, opts ...containers.Option[CreateOption]) (Bunch, error) {
   118→	var options CreateOption
   119→	containers.ApplyAll(&options, opts...)
   120→
   121→	repo, tag, _ := strings.Cut(options.Ref, ":")
   122→
   123→	store, err := oci.New(filepath.Join(s.dir, repo))
   124→	if err != nil {
   125→		return Bunch{}, err
   126→	}
   127→
   128→	store.AutoSaveIndex = true
   129→
   130→	layers, err := NewPackager(zap.NewNop()).Package(ctx, store, src)
   131→	if err != nil {
   132→		return Bunch{}, err
   133→	}
   134→
   135→	desc, err := oras.PackManifest(ctx, store, oras.PackManifestVersion1_1_RC4, MediaTypeFliptState, oras.PackManifestOptions{
   136→		ManifestAnnotations: map[string]string{},
   137→		Layers:              layers,
   138→	})
   139→	if err != nil {
   140→		return Bunch{}, err
   141→	}
   142→
   143→	if tag != "" {
   144→		if err := store.Tag(ctx, desc, tag); err != nil {
   145→			return Bunch{}, err
   146→		}
   147→	}
   148→
   149→	bunch := Bunch{
   150→		Digest:     desc.Digest,
   151→		Repository: repo,
   152→		Tag:        tag,
   153→	}
   154→
   155→	bunch.CreatedAt, err = parseCreated(desc.Annotations)
   156→	if err != nil {
   157→		return Bunch{}, err
   158→	}
   159→
   160→	return bunch, nil
   161→}
