   172→	}
   173→
   174→	repository.PlainHTTP = true
   175→
   176→	store, err := oci.New(filepath.Join(s.dir, reference.Repository))
   177→	if err != nil {
   178→		return err
   179→	}
   180→
   181→	store.AutoSaveIndex = true
   182→
   183→	desc, err := oras.Copy(ctx, store, reference.Reference, repository, reference.Reference, oras.DefaultCopyOptions)
   184→	if err != nil {
   185→		return err
   186→	}
   187→
   188→	fmt.Println(desc.Digest)
